import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card.tsx';
import { Button } from '@/components/ui/button.tsx';
import { Input } from '@/components/ui/input.tsx';
import { Badge } from '@/components/ui/badge.tsx';
import { Separator } from '@/components/ui/separator.tsx';
import { Search } from 'lucide-react';

interface Product {
  id: string;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
  category: string;
}

const generateRandomProducts = (count: number): Product[] => {
  const products: Product[] = [];
  const adjectives = ['Stylish', 'Modern', 'Classic', 'Elegant', 'Durable', 'Smart', 'Portable', 'Eco-friendly'];
  const nouns = ['Chair', 'Table', 'Lamp', 'Sofa', 'Desk', 'Monitor', 'Keyboard', 'Mouse', 'Speaker', 'Headphones'];
  const categories = ['Electronics', 'Furniture', 'Home Decor', 'Accessories'];

  for (let i = 1; i <= count; i++) {
    const randomAdjective = adjectives[Math.floor(Math.random() * adjectives.length)];
    const randomNoun = nouns[Math.floor(Math.random() * nouns.length)];
    const name = `${randomAdjective} ${randomNoun} ${i}`;
    const price = parseFloat((Math.random() * (500 - 20) + 20).toFixed(2));
    const description = `A high-quality ${name.toLowerCase()} designed for comfort and style. Perfect for any modern home or office setup.`;
    const imageUrl = `https://picsum.photos/seed/${i}/300/200`; // Random image
    const category = categories[Math.floor(Math.random() * categories.length)];

    products.push({
      id: `prod-${i}`,
      name,
      price,
      description,
      imageUrl,
      category,
    });
  }
  return products;
};

const ProductsPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [searchTerm, setSearchTerm] = useState<string>('');

  useEffect(() => {
    // Generate 20 random products on component mount
    setProducts(generateRandomProducts(20));
  }, []);

  const filteredProducts = products.filter(product =>
    product.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-4xl font-bold mb-6">Our Products</h1>
      <Separator className="mb-6" />

      <div className="flex items-center space-x-2 mb-8">
        <Search className="h-5 w-5 text-muted-foreground" />
        <Input
          type="text"
          placeholder="Search products..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="max-w-sm"
        />
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
        {filteredProducts.length > 0 ? (
          filteredProducts.map((product) => (
            <Card key={product.id} className="flex flex-col">
              <img src={product.imageUrl} alt={product.name} className="w-full h-48 object-cover rounded-t-lg" />
              <CardHeader>
                <CardTitle>{product.name}</CardTitle>
                <CardDescription className="line-clamp-2">{product.description}</CardDescription>
              </CardHeader>
              <CardContent className="flex-grow">
                <Badge variant="secondary" className="mb-2">{product.category}</Badge>
                <p className="text-2xl font-semibold">${product.price.toFixed(2)}</p>
              </CardContent>
              <CardFooter>
                <Button className="w-full">Add to Cart</Button>
              </CardFooter>
            </Card>
          ))
        ) : (
          <p className="col-span-full text-center text-muted-foreground">No products found matching your search.</p>
        )}
      </div>
    </div>
  );
};

export default ProductsPage;
